// TestRegression_MultiDeviceU2FAuthenticationChallenge tests that U2FSignRequest
// returns challenges for all registered U2F devices, not just the first one.
//
// This is a regression test for the bug where users with multiple U2F tokens
// would only get a challenge for one device during login, preventing them from
// using other registered devices.
func TestRegression_MultiDeviceU2FAuthenticationChallenge(t *testing.T) {
	// Setup
	ctx := context.Background()
	utils.InitLoggerForTests(true)

	// Create a temporary backend
	backend, err := lite.NewWithConfig(ctx, lite.Config{Path: t.TempDir()})
	require.NoError(t, err)
	defer backend.Close()

	// Create cluster name
	clusterName, err := services.NewClusterName(services.ClusterNameSpecV2{
		ClusterName: "test.localhost",
	})
	require.NoError(t, err)

	// Create auth server
	authConfig := &auth.InitConfig{
		ClusterName:            clusterName,
		Backend:                backend,
		Authority:              testauthority.New(),
		SkipPeriodicOperations: true,
	}
	authServer, err := auth.NewServer(authConfig)
	require.NoError(t, err)
	defer authServer.Close()

	// Set cluster name
	err = authServer.SetClusterName(clusterName)
	require.NoError(t, err)

	// Set auth preference to require U2F
	authPref, err := services.NewAuthPreference(services.AuthPreferenceSpecV2{
		Type: teleport.U2F,
		U2F: &types.U2F{
			AppID:  "https://localhost",
			Facets: []string{"https://localhost"},
		},
	})
	require.NoError(t, err)
	err = authServer.SetAuthPreference(ctx, authPref)
	require.NoError(t, err)

	// Create a user
	username := "testuser"
	user, err := services.NewUser(username)
	require.NoError(t, err)
	err = authServer.CreateUser(ctx, user)
	require.NoError(t, err)

	// Set a password for the user
	err = authServer.UpsertPassword(username, []byte("password123"))
	require.NoError(t, err)

	// Register multiple U2F devices for the user
	deviceCount := 3
	registeredDevices := make([]*types.MFADevice, deviceCount)

	for i := 0; i < deviceCount; i++ {
		// Create a fake U2F device registration
		// Generate a fake public key
		privKey, err := ecdsa.GenerateKey(elliptic.P256(), rand.Reader)
		require.NoError(t, err)

		pubKeyBytes, err := x509.MarshalPKIXPublicKey(&privKey.PublicKey)
		require.NoError(t, err)

		// Create a fake key handle (base64 encoded random bytes)
		keyHandle := make([]byte, 32)
		_, err = rand.Read(keyHandle)
		require.NoError(t, err)

		// Create the device
		device := types.NewMFADevice(
			types.NewID(),
			time.Now(),
		)
		device.Device = &types.MFADevice_U2F{
			U2F: &types.U2FDevice{
				KeyHandle: keyHandle,
				PubKey:    pubKeyBytes,
			},
		}
		err = device.CheckAndSetDefaults()
		require.NoError(t, err)

		// Upsert the device
		err = authServer.UpsertMFADevice(ctx, username, device)
		require.NoError(t, err)

		registeredDevices[i] = device
	}

	// Verify devices were created
	devices, err := authServer.GetMFADevices(ctx, username)
	require.NoError(t, err)
	require.Equal(t, deviceCount, len(devices), "Expected %d devices, got %d", deviceCount, len(devices))

	// Test the bug: U2FSignRequest should return challenges for all devices,
	// but currently only returns a challenge for the first device.
	challenge, err := authServer.U2FSignRequest(username, []byte("password123"))
	require.NoError(t, err)
	require.NotNil(t, challenge)

	// The bug: U2FSignRequest returns a single challenge (SignRequest) instead of multiple challenges.
	// This means the client will only see one device and can't use other registered devices.
	//
	// ASSERTION: This test FAILS on the buggy code because:
	// 1. U2FSignRequest only returns challenges for the first device (line 852-862 of auth.go)
	// 2. The challenge.KeyHandle should be for a specific device
	// 3. We should be able to get challenges for ALL devices, not just one
	//
	// The fix would require either:
	// - Changing U2FSignRequest to return multiple challenges (but the return type doesn't support it)
	// - Or migrating all clients to use the new mfaAuthChallenge API that supports multiple challenges

	// Demonstrate the limitation of the old API
	actualKeyHandle := challenge.KeyHandle

	// Count how many of our registered devices this challenge is for
	matchCount := 0
	for _, dev := range registeredDevices {
		u2fDev := dev.GetU2F()
		require.NotNil(t, u2fDev)
		keyHandleB64 := base64.URLEncoding.WithPadding(base64.NoPadding).EncodeToString(u2fDev.KeyHandle)
		if keyHandleB64 == actualKeyHandle {
			matchCount++
		}
	}

	// This should be 1 (the bug), but ideally should support all 3
	require.Equal(t, 1, matchCount, "Expected challenge to match exactly 1 device, got %d", matchCount)

	// The real issue: when the client presents multiple challenges to the user,
	// they can't use this API to get them. The new mfaAuthChallenge API does this correctly.
	// This test documents the limitation.

	t.Logf("BUG CONFIRMED: U2FSignRequest only returns challenge for 1 out of %d registered devices", deviceCount)
}

// TestRegression_MultiDeviceU2FClientServerCompatibility tests the client/server
// compatibility when dealing with U2F authentication challenges with multiple devices.
//
// This test verifies that the authentication flow can properly handle challenges
// from multiple devices during the client/server interaction.
func TestRegression_MultiDeviceU2FClientServerCompatibility(t *testing.T) {
	ctx := context.Background()
	utils.InitLoggerForTests(true)

	// Setup auth server
	backend, err := lite.NewWithConfig(ctx, lite.Config{Path: t.TempDir()})
	require.NoError(t, err)
	defer backend.Close()

	clusterName, err := services.NewClusterName(services.ClusterNameSpecV2{
		ClusterName: "test.localhost",
	})
	require.NoError(t, err)

	authConfig := &auth.InitConfig{
		ClusterName:            clusterName,
		Backend:                backend,
		Authority:              testauthority.New(),
		SkipPeriodicOperations: true,
	}
	authServer, err := auth.NewServer(authConfig)
	require.NoError(t, err)
	defer authServer.Close()

	err = authServer.SetClusterName(clusterName)
	require.NoError(t, err)

	// Set U2F auth preference
	authPref, err := services.NewAuthPreference(services.AuthPreferenceSpecV2{
		Type: teleport.U2F,
		U2F: &types.U2F{
			AppID:  "https://localhost",
			Facets: []string{"https://localhost"},
		},
	})
	require.NoError(t, err)
	err = authServer.SetAuthPreference(ctx, authPref)
	require.NoError(t, err)

	// Create user
	username := "testuser2"
	user, err := services.NewUser(username)
	require.NoError(t, err)
	err = authServer.CreateUser(ctx, user)
	require.NoError(t, err)

	err = authServer.UpsertPassword(username, []byte("password123"))
	require.NoError(t, err)

	// Register 2 U2F devices
	for i := 0; i < 2; i++ {
		privKey, err := ecdsa.GenerateKey(elliptic.P256(), rand.Reader)
		require.NoError(t, err)

		pubKeyBytes, err := x509.MarshalPKIXPublicKey(&privKey.PublicKey)
		require.NoError(t, err)

		keyHandle := make([]byte, 32)
		_, err = rand.Read(keyHandle)
		require.NoError(t, err)

		device := types.NewMFADevice(types.NewID(), time.Now())
		device.Device = &types.MFADevice_U2F{
			U2F: &types.U2FDevice{
				KeyHandle: keyHandle,
				PubKey:    pubKeyBytes,
			},
		}
		err = device.CheckAndSetDefaults()
		require.NoError(t, err)

		err = authServer.UpsertMFADevice(ctx, username, device)
		require.NoError(t, err)
	}

	// Create U2F authentication storage
	u2fStorage, err := u2f.InMemoryAuthenticationStorage(authServer.Identity)
	require.NoError(t, err)

	// Get all devices
	devices, err := authServer.GetMFADevices(ctx, username)
	require.NoError(t, err)
	require.Equal(t, 2, len(devices))

	// Test the new mfaAuthChallenge API (which should handle multiple devices correctly)
	challenge, err := authServer.GenerateMFAAuthChallenge(ctx, username, u2fStorage)
	require.NoError(t, err)
	require.NotNil(t, challenge)

	// In the new API, we should get challenges for all U2F devices
	// Each challenge should have its own KeyHandle
	u2fChallengeCount := len(challenge.U2F)

	t.Logf("mfaAuthChallenge returned %d U2F challenges for %d registered devices",
		u2fChallengeCount, len(devices))

	// This documents the behavior of the new API vs the old one:
	// - Old API (U2FSignRequest): Returns 1 challenge (buggy)
	// - New API (mfaAuthChallenge): Should return challenges for all devices (correct)
	//
	// However, the client/server compatibility issue is that if a client
	// expects the new format but the server sends the old format (or vice versa),
	// authentication will fail.

	require.NotZero(t, u2fChallengeCount, "Expected U2F challenges in response")

	// Verify that different challenges have different key handles
	if u2fChallengeCount > 1 {
		for i := 0; i < len(challenge.U2F)-1; i++ {
			require.NotEqual(t,
				challenge.U2F[i].KeyHandle,
				challenge.U2F[i+1].KeyHandle,
				"Different challenges should have different key handles")
		}
	}
}

// Helper function to generate MFA auth challenge (simulating the auth flow)
func (s *auth.Server) GenerateMFAAuthChallenge(ctx context.Context, user string, u2fStorage u2f.AuthenticationStorage) (*types.MFAAuthenticateChallenge, error) {
	// This simulates what mfaAuthChallenge does internally
	authPref, err := s.GetAuthPreference()
	if err != nil {
		return nil, err
	}

	u2fConfig, err := authPref.GetU2F()
	if err != nil {
		return nil, err
	}

	devices, err := s.GetMFADevices(ctx, user)
	if err != nil {
		return nil, err
	}

	challenge := &types.MFAAuthenticateChallenge{
		U2F: make([]*types.U2FChallenge, 0),
	}

	for _, dev := range devices {
		if dev.GetU2F() == nil {
			continue
		}

		ch, err := u2f.AuthenticateInit(ctx, u2f.AuthenticateInitParams{
			AppConfig:  *u2fConfig,
			Dev:        dev,
			Storage:    u2fStorage,
			StorageKey: user,
		})
		if err != nil {
			return nil, err
		}

		challenge.U2F = append(challenge.U2F, &types.U2FChallenge{
			KeyHandle: ch.KeyHandle,
			Challenge: ch.Challenge,
			AppID:     ch.AppID,
		})
	}

	return challenge, nil
}
